# coding: utf-8
import enum
from functools import wraps
from typing import Dict, List, TYPE_CHECKING

from rainbow_admin.errors import RainbowException
from rainbow_admin.group import BaseGroup
from rainbow_admin.utils import logger

if TYPE_CHECKING:
    from rainbow_admin import RainbowAdmin


class ColumnValueType(enum.IntEnum):
    NUM = 1
    STR = 2
    TEXT = 3
    JSON = 4
    XML = 5
    COLOR = 8
    SELECT = 10
    BOOL = 11
    AUTO_ID = 12
    HREF = 16
    DATETIME = 17
    OWNER = 15


class ColumnType(object):
    column_types: Dict[int, "ColumnType"] = {}

    def __init__(
        self,
        value_type,
        type_name,
        default_en_name,
        default_ch_name,
        has_default_value,
        default_value,
        has_max_length,
        default_max_length,
        is_system_reserved,
        is_read_only,
        is_unique,
        sql_type,
        unique_able,
        can_set_value_list,
        required,
        **kwargs,
    ):
        self.can_set_value_list = can_set_value_list
        self.default_ch_name = default_ch_name
        self.default_en_name = default_en_name
        self.default_max_length = default_max_length
        self.default_value = default_value
        self.has_default_value = has_default_value
        self.has_max_length = has_max_length
        self.is_read_only = is_read_only
        self.is_system_reserved = is_system_reserved
        self.is_unique = is_unique
        self.sql_type = sql_type
        self.type_name = type_name
        self.unique_able = unique_able
        self.value_type = value_type
        self.required = required

    @classmethod
    def register(cls, value_type_id, *args, **kwargs):
        cls.column_types[value_type_id] = cls(value_type_id, *args, **kwargs)

    @classmethod
    def default_column(cls, value_type_id: int, en_name: str, ch_name: str) -> "Column":
        """生成带有默认属性的column
        可用类型: {1: '数字', 2: '字符串', 3: '文本', 4: 'JSON', 5: 'XML',
        8: '颜色', 10: '下拉框', 11: 'BOOL', 12: '自增ID', 16: '链接', 17: '时间',
         15: '负责人'}"""
        column_type = cls.column_types[value_type_id]
        return Column(
            0,
            column_type.value_type,
            en_name,
            ch_name,
            "",
            column_type.default_value,
            column_type.default_max_length,
            column_type.is_unique,
            column_type.is_read_only,
            column_type.required,
        )

    @classmethod
    def init(cls, admin: "RainbowAdmin"):
        """调用接口获取所有类型和他们的默认属性"""
        if not cls.column_types:
            types = admin.api.query_column_types()
            for type_ in types:
                type_id = type_.pop("value_type")
                cls.register(type_id, **type_)


class Column(object):
    def __init__(
        self,
        column_id,
        value_type,
        en_name,
        ch_name,
        value_list,
        default_value,
        max_length=0,
        is_unique=False,
        is_read_only=False,
        required=False,
        display_seq=0,
        is_display=0,
        **kwargs,
    ):
        self.column_id = column_id
        self.value_type = value_type
        self.en_name = en_name
        self.ch_name = ch_name
        self.value_list = value_list
        self.default_value = default_value
        self.max_length = max_length
        self.is_unique = is_unique
        self.is_read_only = is_read_only
        self.required = required

        self.display_seq = display_seq
        self.is_display = is_display
        if "sql_type" in kwargs:
            self.sql_type = kwargs["sql_type"]
        else:
            column_type = ColumnType.column_types.get(value_type)
            if column_type:
                self.sql_type = column_type.sql_type
            else:
                logger.warning(
                    f"can't find sql_type of value_type '{value_type}', use text"
                )
                self.sql_type = "text"
        self.sql_op_type = kwargs.get("sql_op_type", "COLUMNOP_ADD")

    def to_dict(self):
        return {
            "value_type": self.value_type,
            "default_value": self.default_value,
            "en_name": self.en_name,
            "ch_name": self.ch_name,
            "is_unique": self.is_unique,
            "is_read_only": self.is_read_only,
            "display_seq": self.display_seq,
            "sql_type": self.sql_type,
            "sql_op_type": self.sql_op_type,
            "max_length": self.max_length,
            "value_list": self.value_list,
            "required": self.required,
            "is_display": self.is_display,
        }

    def __str__(self) -> str:
        return f"{self.__class__.__name__}(name={self.ch_name})"

    __repr__ = __str__


def check_table_created(func):
    @wraps(func)
    def wrapper(self, *args, **kwargs):
        if self.table_id == 0:
            raise ValueError(f"分组{self.group_id}未创建表，请先创建表")
        else:
            if self.table_info is None:
                self.init_table()
            return func(self, *args, **kwargs)

    return wrapper


class TableGroup(BaseGroup):
    OP_ADD = "ROWOP_ADD"
    OP_DELETE = "ROWOP_DELETE"
    OP_UPDATE = "ROWOP_UPDATE"

    CONFIG_TYPE = 1

    def __init__(
        self,
        group_id=None,
        group_name=None,
        description="",
        config_type=0,
        admin: "RainbowAdmin" = None,
        **kwargs,
    ):
        super().__init__(
            group_id, group_name, description, config_type, admin, **kwargs
        )
        self.table_id = kwargs.get("table_id")
        self.description = description
        self.is_row_auth_open = kwargs.get("is_row_auth_open", False)
        self.table_info = None

        if not ColumnType.column_types:
            try:
                ColumnType.init(self.admin)
            except Exception as e:
                logger.warning(f"query column types fail: {e}")

    def init_table(self):
        """table分组可能还没有创建表，延迟判断，通过 @check_table_created 装饰器，在实际执行方法的时候"""
        infos = self.admin.api.query_table(self.group_id, self.table_id)
        infos.update(**infos.pop("table_info"))
        self.en_name = infos["en_name"]
        self.columns = [Column(**i) for i in infos["column_infos"]]
        self.columns.sort(key=lambda x: x.display_seq)
        self._columns_map = {i.en_name: i for i in self.columns}
        self.table_info = infos

    @property
    @check_table_created
    def table(self):
        """为了向前兼容"""
        return self

    @check_table_created
    def get_info(self, version_id=0, version_name=None):
        if version_name:
            l = list(
                filter(lambda x: x['version_name'] == version_name, self.history_versions)
            )
            if len(l) == 0:
                raise RainbowException("历史版本中查不到指定的版本名 {verison_name}")
            if version_id and version_id != l[0]['version_id']:
                raise RainbowException("同时指定了version_id和version_name，但根据name查询到的id不一致 {verison_name}")
            version_id = l[0]['version_id']
        return self.admin.api.query_row_data(
            self.group_id, self.table_id, 0, version_id
        )

    @property
    def data(self) -> List[Dict[str, str]]:
        return [
            {j["key"]: j["value"] for j in i["column_datas"]}
            for i in self.get_info()["table_config_info"]["datas"]
        ]

    @property
    @check_table_created
    def headers(self):
        return [i.en_name for i in self.columns]

    @property
    @check_table_created
    def headers_ch(self):
        return [i.ch_name for i in self.columns]

    def __len__(self):
        return self.get_info()["table_config_info"]["total_num"]

    @check_table_created
    def delete(self, *row_id: int):
        payload = [{"op_type": self.OP_DELETE, "row_id": i} for i in row_id]
        self.admin.api.change_row_data(self.group_id, self.table_id, payload)

    @check_table_created
    def delete_rows(self, row_ids: List[int]):
        row_id = tuple(row_ids)
        self.delete(*row_id)

    @check_table_created
    def update(self, row_id: int, data: dict):
        data["_auto_id"] = str(row_id)
        payload = [
            {
                "row_id": row_id,
                "op_type": self.OP_UPDATE,
                "column_datas": [{"key": k, "value": v} for k, v in data.items()],
            }
        ]
        self.admin.api.change_row_data(self.group_id, self.table_id, payload)

    @check_table_created
    def update_rows(self, rows: List[Dict[str, str]]):
        """批量更新多行的字段值
        :param  rows: List[Dict], Dict 是 {"column_name": "column_value", ...} 的 dict 结构
        可以通过 table 分组的 data 属性获取 dict 结构的所有行。对每行，更新其中的字段值，再封装为 list 结构

        举例有如下 rows:
            [
                {
                    "_auto_id": "1",
                    "col_a": "aaa",
                    "col_b": "xxx",
                }
                # ...... 这里省略其他行
            ]
        更新 _auto_id = 1 的 col_a 字段值，则传入参数 rows 可以是：
            [
                {
                    "_auto_id": "1",
                    "col_a": "changed this",
                    "col_b": "xxx",
                }
            ]
        也可以只传入有更新的字段 col_a，但必须额外传 _auto_id 字段：
            [
                {
                    "_auto_id": "1",
                    "col_a": "changed this",
                }
            ]
        """
        payload = list()
        for row in rows:
            payload.append({
                "row_id": row['_auto_id'],
                "op_type": self.OP_UPDATE,
                "column_datas": [{"key": k, "value": str(v)} for k, v in row.items()],
            })
        self.admin.api.change_row_data(self.group_id, self.table_id, payload)

    @check_table_created
    def add(self, data: dict) -> int:
        """添加一项纪录，为key形式，要求所有value都是string"""
        data["_auto_id"] = ""
        payload = [
            {
                "op_type": self.OP_ADD,
                "column_datas": [{"key": k, "value": v} for k, v in data.items()],
            }
        ]
        result = self.admin.api.change_row_data(self.group_id, self.table_id, payload)
        if result:
            row_id = result[0]["row_id"]
            data["_auto_id"] = str(row_id)
            return row_id
        return 0

    @check_table_created
    def add_rows(self, rows: List[Dict[str, str]]) -> List[int]:
        """批量新增多行
        :param  rows: List[Dict], Dict 是 {"column_name": "column_value", ...} 的 dict 结构

        :return  List[int]: 新增的行的 row_id 列表
        """
        payload = list()
        if len(rows) == 0:
            return []

        for row in rows:
            payload.append({
                "op_type": self.OP_ADD,
                "column_datas": [{"key": k, "value": str(v)} for k, v in row.items()],
            })
        result = self.admin.api.change_row_data(self.group_id, self.table_id, payload)
        if result:
            return [item['row_id'] for item in result]
        return []

    @check_table_created
    def get(self, row_id):
        select = [i for i in self.data if str(i["_auto_id"]) == str(row_id)]
        return select[0] if select else None

    def create_table(self, name, description, columns: List[Column]) -> int:
        """table型分组创建表

        :param name: table name
        :param description:  table description
        :param columns: Column类型的list，可以通过`ColumnType.default_column`获取column的默认参数，
        注意list的第一项必须是自增id， 通过`ColumnType.default_column(12, "_auto_id", "id")`生成
        :return:
        """
        columns = [i.to_dict() for i in columns]
        for i, column in enumerate(columns):
            column["display_seq"] = i + 1
        table_id = self.admin.api.create_table(
            self.group_id, name, description, columns, False
        )
        self.table_id = table_id
        return table_id

    def to_dataframe(self):
        import pandas as pd

        return pd.DataFrame(self.data)
